class TokenStore:
    """Manages authentication tokens and their associated roles."""

    def __init__(self):
        self._tokens = {}  # token -> {"user": str, "roles": set, "created": float}
        self._rate_limits = defaultdict(list)  # ip -> [timestamps]
        self._failed_attempts = defaultdict(int)  # token_prefix -> count
        self._lockout_until = {}  # token_prefix -> timestamp

    def register_token(self, user: str, roles: Set[str]) -> str:
        """Generate and register a new token for a user with given roles."""
        token = secrets.token_urlsafe(48)
        self._tokens[self._hash_token(token)] = {
            "user": user,
            "roles": roles,
            "created": time.time(),
        }
        logger.info(f"Registered token for user '{user}' with roles {roles}")
        return token

    def validate_token(self, token: str) -> Optional[dict]:
        """Validate a token and return user info if valid."""
        hashed = self._hash_token(token)

        # Check lockout
        token_prefix = token[:8] if len(token) >= 8 else token
        if token_prefix in self._lockout_until:
            if time.time() < self._lockout_until[token_prefix]:
                logger.warning(f"Token prefix {token_prefix}... is locked out")
                return None
            else:
                del self._lockout_until[token_prefix]
                self._failed_attempts[token_prefix] = 0

        info = self._tokens.get(hashed)
        if info is None:
            self._failed_attempts[token_prefix] += 1
            if self._failed_attempts[token_prefix] >= 5:
                self._lockout_until[token_prefix] = time.time() + 300  # 5 min lockout
                logger.warning(f"Token prefix {token_prefix}... locked out after 5 failed attempts")
            return None

        return info

    def revoke_token(self, token: str) -> bool:
        """Revoke a token."""
        hashed = self._hash_token(token)
        if hashed in self._tokens:
            user = self._tokens[hashed]["user"]
            del self._tokens[hashed]
            logger.info(f"Revoked token for user '{user}'")
            return True
        return False

    @staticmethod
    def _hash_token(token: str) -> str:
        """Hash token for secure storage."""
        return hashlib.sha256(token.encode('utf-8')).hexdigest()


