class RateLimitInterceptor(ServerInterceptor):
    """Rate limiting interceptor to prevent abuse."""

    def __init__(self, max_requests_per_minute: int = 100):
        self._max_rpm = max_requests_per_minute
        self._request_log = defaultdict(list)  # peer -> [timestamps]

    def intercept_service(self, continuation, handler_call_details):
        metadata = dict(handler_call_details.invocation_metadata or [])
        peer = metadata.get("x-forwarded-for", "unknown")

        now = time.time()
        window_start = now - 60

        # Clean old entries
        self._request_log[peer] = [
            t for t in self._request_log[peer] if t > window_start
        ]

        if len(self._request_log[peer]) >= self._max_rpm:
            logger.warning(f"Rate limit exceeded for peer {peer}")

            def _rate_limited(request, context):
                context.abort(
                    grpc.StatusCode.RESOURCE_EXHAUSTED,
                    f"Rate limit exceeded. Max {self._max_rpm} requests per minute."
                )

            return grpc.unary_unary_rpc_method_handler(_rate_limited)

        self._request_log[peer].append(now)
        return continuation(handler_call_details)


