def create_server(
    port: int = 50051,
    max_workers: int = 10,
    enable_tls: bool = True,
    server_cert_path: Optional[str] = None,
    server_key_path: Optional[str] = None,
    ca_cert_path: Optional[str] = None,
) -> grpc.Server:
    """
    Create and configure the gRPC server with security interceptors.

    Args:
        port: Port to listen on
        max_workers: Max thread pool workers
        enable_tls: Whether to enable TLS (strongly recommended)
        server_cert_path: Path to server certificate
        server_key_path: Path to server private key
        ca_cert_path: Path to CA certificate for client verification
    """

    # Create interceptors (order matters - audit first, then rate limit, then auth)
    interceptors = [
        AuditLoggingInterceptor(),
        RateLimitInterceptor(max_requests_per_minute=200),
        AuthenticationInterceptor(token_store),
    ]

    server = grpc.server(
        futures.ThreadPoolExecutor(max_workers=max_workers),
        interceptors=interceptors,
    )

    # Register services
    # In production, you'd register your actual generated servicers here:
    # example_pb2_grpc.add_ExampleServiceServicer_to_server(ExampleServiceServicer(), server)
    # admin_pb2_grpc.add_AdminServiceServicer_to_server(AdminServiceServicer(), server)
    # metrics_pb2_grpc.add_MetricsServiceServicer_to_server(MetricsServiceServicer(), server)

    # Health check service (standard gRPC health checking)
    from grpc_health.v1 import health
    health_servicer = health.HealthServicer()
    health_pb2_grpc.add_HealthServicer_to_server(health_servicer, server)

    # Configure port with or without TLS
    if enable_tls:
        if not all([server_cert_path, server_key_path]):
            raise ValueError(
                "TLS is enabled but server_cert_path and server_key_path are required. "
                "Set enable_tls=False only for local development."
            )

        with open(server_key_path, 'rb') as f:
            server_key = f.read()
        with open(server_cert_path, 'rb') as f:
            server_cert = f.read()

        ca_cert = None
        if ca_cert_path:
            with open(ca_cert_path, 'rb') as f:
                ca_cert = f.read()

        if ca_cert:
            # Mutual TLS - strongest option
            credentials = grpc.ssl_server_credentials(
                [(server_key, server_cert)],
                root_certificates=ca_cert,
                require_client_auth=True,
            )
            logger.info("Server configured with mutual TLS (mTLS)")
        else:
            credentials = grpc.ssl_server_credentials(
                [(server_key, server_cert)]
            )
            logger.info("Server configured with server-side TLS")

        server.add_secure_port(f"[::]:{port}", credentials)
    else:
        logger.warning(
            "⚠️  TLS is DISABLED. This should only be used for local development!"
        )
        server.add_insecure_port(f"[::]:{port}")

    return server


