def serve():
    """Start the gRPC server."""
    import argparse

    parser = argparse.ArgumentParser(description="Secure gRPC Server")
    parser.add_argument("--port", type=int, default=50051, help="Server port")
    parser.add_argument("--no-tls", action="store_true", help="Disable TLS (dev only)")
    parser.add_argument("--cert", type=str, help="Server certificate path")
    parser.add_argument("--key", type=str, help="Server private key path")
    parser.add_argument("--ca", type=str, help="CA certificate path (for mTLS)")
    parser.add_argument("--demo", action="store_true", help="Set up demo tokens")
    args = parser.parse_args()

    if args.demo:
        setup_demo_tokens()

    try:
        server = create_server(
            port=args.port,
            enable_tls=not args.no_tls,
            server_cert_path=args.cert,
            server_key_path=args.key,
            ca_cert_path=args.ca,
        )
    except ValueError as e:
        logger.error(str(e))
        logger.info("For local development, use --no-tls flag")
        return

    server.start()
    logger.info(f"Server started on port {args.port}")
    logger.info("Press Ctrl+C to stop")

    try:
        server.wait_for_termination()
    except KeyboardInterrupt:
        logger.info("Shutting down server...")
        server.stop(grace=5)
        logger.info("Server stopped")


if __name__ == "__main__":
    serve()